// Cross-implementation conformance: TypeScript reads the Rust-produced corpus.
//
// This is the first second-language proof for phon's self-describing `Value`
// wire format. The corpus under `conformance/values/*.phon` is generated by the
// Rust oracle (`rust/phon-conformance`); these vectors are schema-less single
// values whose bytes are the golden.
//
// CHECK MECHANISM — round-trip, per `conformance/README.md`: "The oracle for a
// value is: decode it, re-encode, and get byte-identical output ... since values
// carry no schema and no id." There is no expected-value manifest (the `.phon`
// files are raw bytes only), so byte-identical re-encode is the available and
// intended oracle. It proves TS implements the *same* format Rust produced: a
// wrong tag, endianness slip, or length-prefix error changes the bytes and fails.
//
// We additionally pin the *decoded value* for a representative slice of vectors.
// Round-trip alone can pass for a decoder/encoder pair that is internally
// symmetric but mis-reads (e.g. swaps two fields consistently); pinning the
// decoded JS value rules that out and proves TS reads Rust's bytes to the right
// values — the actual interop claim.

import { readFileSync, readdirSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { describe, expect, it } from "vitest";

import { decodeValue, encodeValue, type Value } from "./value.ts";
import { DecodeError } from "./wire.ts";

const HERE = dirname(fileURLToPath(import.meta.url));
// .../typescript/packages/phon-schema/src -> repo root is four levels up.
const REPO_ROOT = join(HERE, "..", "..", "..", "..");
const VALUES_DIR = join(REPO_ROOT, "conformance", "values");

function valueFiles(): string[] {
  return readdirSync(VALUES_DIR)
    .filter((f) => f.endsWith(".phon"))
    .toSorted();
}

function readVector(name: string): Uint8Array {
  return new Uint8Array(readFileSync(join(VALUES_DIR, name)));
}

// r[verify value]
// r[verify self-describing.tag-led]
describe("conformance/values round-trip (TS reads Rust-produced bytes)", () => {
  const files = valueFiles();

  it("the corpus is present and non-empty", () => {
    expect(files.length).toBeGreaterThan(0);
  });

  for (const name of files) {
    it(`${name}: decode then re-encode is byte-identical`, () => {
      const bytes = readVector(name);
      const value = decodeValue(bytes);
      const reencoded = encodeValue(value);
      expect(Array.from(reencoded)).toEqual(Array.from(bytes));
    });
  }
});

describe("conformance/values decoded-value assertions", () => {
  // A representative slice: scalars across every integer width, float, the
  // containers, and each extended kind. These pin that TS reads Rust's bytes to
  // the *right* value, not merely a self-consistent one.

  it("null -> null", () => {
    expect(decodeValue(readVector("null.phon"))).toBeNull();
  });

  it("bool_true / bool_false", () => {
    expect(decodeValue(readVector("bool_true.phon"))).toBe(true);
    expect(decodeValue(readVector("bool_false.phon"))).toBe(false);
  });

  it("integers decode to exact bigints across every width", () => {
    expect(decodeValue(readVector("int_small.phon"))).toBe(42n);
    expect(decodeValue(readVector("int_negative.phon"))).toBe(-7n);
    expect(decodeValue(readVector("int_u64_max.phon"))).toBe((1n << 64n) - 1n);
    expect(decodeValue(readVector("int_u128_max.phon"))).toBe((1n << 128n) - 1n);
    expect(decodeValue(readVector("int_i128_min.phon"))).toBe(-(1n << 127n));
  });

  it("float decodes to 2.5", () => {
    expect(decodeValue(readVector("float.phon"))).toBe(2.5);
  });

  it("string decodes the UTF-8 sample verbatim", () => {
    expect(decodeValue(readVector("string.phon"))).toBe("héllo λ 🌍");
  });

  it("bytes decode to the exact byte run", () => {
    const v = decodeValue(readVector("bytes.phon"));
    expect(v).toBeInstanceOf(Uint8Array);
    expect(Array.from(v as Uint8Array)).toEqual([0, 1, 2, 254, 255]);
  });

  it("char decodes to a tagged Unicode scalar", () => {
    const v = decodeValue(readVector("char.phon"));
    expect(v).toEqual({ kind: "char", value: "λ" });
  });

  it("array folds list to a flat JS array [1, 'x', null, true]", () => {
    const v = decodeValue(readVector("array.phon")) as Value[];
    expect(Array.isArray(v)).toBe(true);
    expect(v[0]).toBe(1n);
    expect(v[1]).toBe("x");
    expect(v[2]).toBeNull();
    expect(v[3]).toBe(true);
  });

  it("object folds map to a string-keyed Map in field order", () => {
    const v = decodeValue(readVector("object.phon"));
    expect(v).toBeInstanceOf(Map);
    const o = v as Map<string, Value>;
    expect([...o.keys()]).toEqual(["a", "b", "c"]);
    expect(o.get("a")).toBe(1n);
    expect(o.get("b")).toBe(true);
    expect(o.get("c")).toEqual([{ kind: "char", value: "z" }]);
  });

  // r[verify self-describing.enum-payload]
  it("enum folds to a one-entry Map whose value is the single payload value", () => {
    const unit = decodeValue(new Uint8Array([
      0x17,
      0x04, 0x00, 0x00, 0x00,
      0x4e, 0x69, 0x6c, 0x73,
      0x00,
    ]));
    expect(unit).toEqual(new Map([["Nils", null]]));

    const tuple = decodeValue(new Uint8Array([
      0x17,
      0x04, 0x00, 0x00, 0x00,
      0x50, 0x61, 0x69, 0x72,
      0x15,
      0x02, 0x00, 0x00, 0x00,
      0x0a, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
      0x0f, 0x01, 0x00, 0x00, 0x00, 0x78,
    ]));
    expect(tuple).toEqual(new Map([["Pair", [1n, "x"]]]));

    const struct = decodeValue(new Uint8Array([
      0x17,
      0x06, 0x00, 0x00, 0x00,
      0x50, 0x6f, 0x69, 0x6e, 0x74, 0x79,
      0x16,
      0x05, 0x00, 0x00, 0x00,
      0x50, 0x6f, 0x69, 0x6e, 0x74,
      0x02, 0x00, 0x00, 0x00,
      0x01, 0x00, 0x00, 0x00,
      0x78,
      0x0a, 0x02, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
      0x01, 0x00, 0x00, 0x00,
      0x79,
      0x0a, 0x03, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
    ]));
    expect(struct).toEqual(new Map([[
      "Pointy",
      new Map<string, Value>([
        ["x", 2n],
        ["y", 3n],
      ]),
    ]]));
  });

  // r[verify value.extended-kinds]
  it("uuid decodes to its canonical string", () => {
    expect(decodeValue(readVector("uuid.phon"))).toEqual({
      kind: "uuid",
      text: "01234567-89ab-cdef-fedc-ba9876543210",
    });
  });

  // r[verify value.extended-kinds]
  it("qname namespaced and local", () => {
    expect(decodeValue(readVector("qname_namespaced.phon"))).toEqual({
      kind: "qname",
      namespace: "http://ex.com/ns",
      local: "el",
    });
    expect(decodeValue(readVector("qname_local.phon"))).toEqual({
      kind: "qname",
      namespace: null,
      local: "el",
    });
  });

  // r[verify value.extended-kinds]
  it("datetime shapes decode with the right discriminant", () => {
    expect(decodeValue(readVector("datetime_date.phon"))).toMatchObject({ shape: "date", year: 2026, month: 5, day: 29 });
    expect(decodeValue(readVector("datetime_time.phon"))).toMatchObject({ shape: "time", hour: 7, minute: 32, second: 0, nanos: 500 });
    expect(decodeValue(readVector("datetime_local.phon"))).toMatchObject({ shape: "localDateTime", year: 2026, hour: 7 });
    expect(decodeValue(readVector("datetime_utc.phon"))).toMatchObject({ shape: "offset", offsetMinutes: 0 });
    expect(decodeValue(readVector("datetime_offset.phon"))).toMatchObject({ shape: "offset", offsetMinutes: 330, nanos: 123456789 });
  });

  // r[verify validate.tags]
  // r[verify self-describing.no-extra-kinds]
  it("rejects an unknown self-describing tag", () => {
    expect(() => decodeValue(new Uint8Array([0xff]))).toThrow(DecodeError);
    expect(() => decodeValue(new Uint8Array([0xff]))).toThrow(/unknown tag/);
  });

  // r[verify validate.depth]
  it("rejects excessive self-describing nesting depth", () => {
    const bytes: number[] = [];
    for (let i = 0; i < 130; i++) {
      bytes.push(0x11, 1, 0, 0, 0);
    }
    bytes.push(0x18);
    expect(() => decodeValue(new Uint8Array(bytes))).toThrow(DecodeError);
    expect(() => decodeValue(new Uint8Array(bytes))).toThrow(/maximum nesting depth/);
  });
});
